t.script:
                (function () {
                    var rawData = document.getElementById('craft-region-data').textContent;
                    var regions = JSON.parse(rawData);

                    var map = L.map('craft-map').setView([22.5, 80.0], 5);

                    L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
                        attribution: '© OpenStreetMap contributors',
                        maxZoom: 18,
                    }).addTo(map);

                    var panel     = document.getElementById('region-panel');
                    var rpName    = document.getElementById('rp-name');
                    var rpState   = document.getElementById('rp-state');
                    var rpTrad    = document.getElementById('rp-tradition');
                    var rpDesign  = document.getElementById('rp-designers');

                    regions.forEach(function (r) {
                        if (!r.lat || !r.lng) return;

                        var marker = L.circleMarker([r.lat, r.lng], {
                            radius:      r.designer_count > 0 ? 10 + r.designer_count * 2 : 10,
                            fillColor:   '#1D9E75',
                            color:       '#0F6E56',
                            weight:      2,
                            opacity:     1,
                            fillOpacity: 0.75,
                        }).addTo(map);

                        marker.bindTooltip(r.name + ' (' + r.designer_count + ' designer' +
                            (r.designer_count !== 1 ? 's' : '') + ')', {sticky: true});

                        marker.on('click', function () {
                            rpName.textContent   = r.name;
                            rpState.textContent  = r.state || '';
                            rpTrad.textContent   = r.tradition || 'No tradition description available.';
                            rpDesign.innerHTML   = 'Loading designers…';
                            panel.classList.remove('d-none');
                            panel.scrollIntoView({behavior: 'smooth', block: 'nearest'});

                            fetch('/craft-map/region/' + r.id, {
                                method: 'POST',
                                headers: {'Content-Type': 'application/json'},
                                body: JSON.stringify({jsonrpc:'2.0',method:'call',params:{}}),
                            })
                            .then(function (res) { return res.json(); })
                            .then(function (data) {
                                var designers = (data.result || {}).designers || [];
                                if (!designers.length) {
                                    rpDesign.innerHTML = '
No designers linked to this region yet.';
                                    return;
                                }
                                rpDesign.innerHTML = designers.map(function (d) {
                                    var link = d.published
                                        ? '' + d.name + ''
                                        : '' + d.name + '';
                                    return '
' + link +
                                        (d.specialty ? ' — ' + d.specialty + '' : '') +
                                        '';
                                }).join('');
                            })
                            .catch(function () {
                                rpDesign.innerHTML = '
Could not load designer info.';
                            });
                        });
                    });
                })();
